import{_ as a,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Relevadores de Seguridad","description":"","frontmatter":{},"headers":[],"relativePath":"es/safety/safety-relays.md","filePath":"es/safety/safety-relays.md"}'),r={name:"es/safety/safety-relays.md"};function d(n,e,l,t,c,u){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="relevadores-de-seguridad" tabindex="-1">Relevadores de Seguridad <a class="header-anchor" href="#relevadores-de-seguridad" aria-label="Permalink to &quot;Relevadores de Seguridad&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los relevadores de seguridad son dispositivos utilizados para monitorear y controlar circuitos de seguridad en sistemas industriales.</p><p>Aseguran que funciones de seguridad como paros de emergencia, puertas de seguridad y enclavamientos operen correctamente y de forma confiable.</p><p>Los relevadores de seguridad están diseñados con detección de fallas integrada y comportamiento a prueba de fallos.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de un relevador de seguridad es asegurar que las funciones de seguridad se ejecuten de forma confiable, incluso en presencia de fallas.</p><p>Se utiliza para:</p><ul><li>Monitorear dispositivos de seguridad</li><li>Detectar fallas en circuitos de seguridad</li><li>Controlar el apagado seguro del equipo</li><li>Asegurar el cumplimiento de los requisitos de seguridad</li></ul><p>Los relevadores de seguridad proporcionan un nivel de confiabilidad superior al de los relevadores estándar.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los relevadores de seguridad monitorean entradas y controlan salidas según las condiciones de seguridad.</p><h3 id="monitoreo-de-entradas" tabindex="-1">Monitoreo de entradas <a class="header-anchor" href="#monitoreo-de-entradas" aria-label="Permalink to &quot;Monitoreo de entradas&quot;">​</a></h3><p>El relevador recibe señales de dispositivos de seguridad.</p><ul><li>Botones de paro de emergencia</li><li>Interruptores de seguridad o cortinas de luz</li></ul><p>Las entradas típicamente son redundantes y se monitorean por consistencia.</p><h3 id="logica-interna" tabindex="-1">Lógica interna <a class="header-anchor" href="#logica-interna" aria-label="Permalink to &quot;Lógica interna&quot;">​</a></h3><p>El relevador de seguridad evalúa las condiciones de entrada.</p><ul><li>Verifica los estados correctos de las señales</li><li>Detecta fallas como cortocircuitos o problemas de cableado</li></ul><p>Los diagnósticos internos aseguran una operación adecuada.</p><h3 id="control-de-salidas" tabindex="-1">Control de salidas <a class="header-anchor" href="#control-de-salidas" aria-label="Permalink to &quot;Control de salidas&quot;">​</a></h3><p>Cuando se cumplen condiciones seguras:</p><ul><li>Las salidas permiten la operación del sistema</li></ul><p>Cuando se detecta una falla o condición insegura:</p><ul><li>Las salidas se desactivan</li><li>El equipo se lleva a un estado seguro</li></ul><h3 id="funcion-de-reinicio" tabindex="-1">Función de reinicio <a class="header-anchor" href="#funcion-de-reinicio" aria-label="Permalink to &quot;Función de reinicio&quot;">​</a></h3><p>Después de un evento de seguridad:</p><ul><li>Generalmente se requiere reinicio manual</li><li>Asegura que las condiciones se verifiquen antes del arranque</li></ul><p>Esto previene la operación no intencionada.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los relevadores de seguridad se utilizan en muchos sistemas industriales.</p><p>Las aplicaciones típicas incluyen:</p><ul><li>Circuitos de paro de emergencia</li><li>Enclavamientos de seguridad en guardas y puertas</li><li>Sistemas de protección con cortinas de luz</li><li>Sistemas de control de dos manos</li></ul><p>Son esenciales en sistemas que requieren seguridad funcional.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>Los requisitos de nivel de seguridad deben coincidir con la aplicación.</p><p>El cableado y la configuración adecuados son críticos.</p><p>La compatibilidad con dispositivos de seguridad debe verificarse.</p><p>El diagnóstico y la detección de fallas mejoran la confiabilidad.</p><p>El cumplimiento de normas de seguridad es obligatorio.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es usar relevadores estándar para funciones de seguridad. Siempre utilizar dispositivos de seguridad certificados.</p><p>Asegurar el cableado correcto de canales redundantes.</p><p>No omitir los circuitos de relevadores de seguridad.</p><p>Probar las funciones de seguridad regularmente.</p><p>Documentar claramente la lógica y las conexiones de seguridad.</p>',46)])])}const g=a(r,[["render",d]]);export{m as __pageData,g as default};
